    if (text_offset >= doc_size) {
        /* Text offset is beyond document size */
        return (char)0xff;
    }

    if (target_position >= doc_size) {
        /* Target position is beyond document size */
        return (char)0xff;
    }

    /* Ensure we're not accessing before the text section */
    if (target_position < text_offset) {
        /* This shouldn't happen with non-negative char_index, but defensive check */
        return (char)0xff;
    }

    /* All checks passed - safe to access the character */
    return (char)doc_data[target_position];
}
